            "airstream/link_with_tv_code_settings_pane.html": '<div>  <div class="link-with-tv-code-img"></div>  <div class="settings-pane-title" aria-hidden="true">{{model.title}}</div>  <div class="settings-pane-step-list">    <div class="settings-pane-step">[[<div class="settings-pane-step-number">1.</div><div class="settings-pane-step-text">On your phone, open the YouTube app.</div>|Enumerated first step to link phone and TV through a pairing code.|248862271]]</div>    <div class="settings-pane-step">[[<div class="settings-pane-step-number">2.</div><div class="settings-pane-step-text">In your phone\'s YouTube settings, tap Watch on TV.</div>|Enumerated second step to link phone and TV through a pairing code.|1408969108]]</div>    <div class="settings-pane-step">[[<div class="settings-pane-step-number">3.</div><div class="settings-pane-step-text">Tap <span class="settings-pane-step-bold">Enter TV code</span> and enter the code below.</div>|Enumerated third step to link phone and TV through a pairing code. \'Enter TV code\' should be equivalent to the translation found here: https://tc.corp.google.com/btviewer/messagedetail?project=YouTubeUI&msgId=6405629164329737131|1607316154]]</div>  </div>  <div class="settings-pane-pairing-code" aria-hidden="true">{{model.pairingCodeText}}</div>  <div class="accessible-pairing-code" aria-live="polite">{{ariaLabelValue}}</div></div>',
            "airstream/link_with_wifi_settings_pane.html": '<div>  <div class="link-with-wifi-img"></div>  <div class="settings-pane-title" aria-hidden="true">{{model.title}}</div>  <div class="settings-pane-step-list">    <div class="settings-pane-step">[[<div class="settings-pane-step-number">1.</div><div class="settings-pane-step-text">On your phone, connect to the same Wi-Fi network as this device.</div>|Enumerated first step to link phone and device through Wi-Fi.|395964336]]</div>    <div class="settings-pane-step">[[<div class="settings-pane-step-number">2.</div><div class="settings-pane-step-text">Open the YouTube app on your phone.</div>|Enumerated second step to link phone and TV through Wi-Fi.|114259054]]</div>    <div class="settings-pane-step">[[<div class="settings-pane-step-number">3.</div><div class="settings-pane-step-text">Tap the cast icon and select this device.</div>|Enumerated third step to link phone and device through Wi-Fi.|545781032]]</div>  </div></div>',
            "airstream/movie_tile.html": '<div class="airstream-video-tile">  <div class="airstream-watch-later-inline-legend">    <div class="watch-later-inline-legend-icon"></div>    <div class="watch-later-inline-legend-text">{{model.watchLaterInlineLegendText}}</div>  </div>  <div class="watchable-tile-top {{parent.model.getClassName()}} $tiltable">    <div class="watchable-tile-thumbnail-background">      <div class="watchable-tile-thumbnail $image" data-image-url="{{parent.model.imageUrl}}"></div>      <div class="airstream-video-tile-animated-thumbnail $image" data-hidden-by-default="true"></div>      <div class="tile-overlay">        <div class="icon {{parent.model.overlayIconClass}}"></div>        <div class="label">{{parent.model.overlayText}}</div>      </div>    </div>    <div class="watchable-tile-overlay">      <div class="airstream-video-tile-progress">        <div class="airstream-video-tile-progress-watched"></div>      </div>      <div class="airstream-video-tile-decoration">        <div class="airstream-video-tile-decoration-text {{parent.model.decoration.decorationClass}}">          {{parent.model.decoration.text}}        </div>      </div>    </div>  </div>  <div class="poster-tile-highlighter"></div>  <div class="$watchable-tile-bottom" data-model="{{model.watchableTileBottom}}"></div></div>',
            "airstream/playlist_tile.html": '<div class="{{getName()}} {{getClassName()}} {{model.getClassName()}}">  <div class="watchable-tile-top $tiltable">    <div class="watchable-tile-thumbnail-background">      <div class="watchable-tile-thumbnail $image" data-image-url="{{parent.model.imageUrl}}"></div>      <div class="collage-thumbnail-container hidden"></div>      <div class="watchable-tile-overlay overlay-background"           bedrock-style="{{parent.model.overlayStyle}}"></div>    </div>    <div class="watchable-tile-overlay overlay-details">      <div class="airstream-playlist-tile-text">{{parent.model.overlayText}}</div>      <div class="airstream-playlist-tile-icon {{parent.model.iconClass}}"></div>    </div>    <div class="airstream-playlist-tile-progress">      <div class="airstream-playlist-tile-progress-watched"></div>    </div>    <div class="airstream-playlist-tile-avatar $image" data-image-url="{{parent.model.avatarUrl}}"></div>    <div class="slideshow-thumbnail-container hidden"></div>  </div>  <div class="$watchable-tile-bottom" data-model="{{model.watchableTileBottom}}"></div></div>',
            "airstream/radio_settings_pane.html": '<div>  <div class="radio-settings-pane-icon {{model.iconClass}}"></div>  <div class="radio-settings-pane-text-container">    <div class="radio-settings-pane-title" aria-hidden="true">{{model.title}}</div>    <div class="radio-settings-pane-subtitle">{{model.subtitle}}</div>  </div>  <div class="radio-settings-pane-button-list $lightweight-list" role="radiogroup" data-model="{{model.radioButtonList.getButtons()}}" data-is-vertical="true"></div></div>',
