            "airstream_app.html": '<div id="app-markup">  <div id="call-to-cast" class="$call-to-cast" data-hidden-by-default="true"></div>  <div id="surface" class="$surface"></div>  <div id="detail-surface" class="hidden"></div>  <div id="channel" class="hidden"></div>  <div id="search" class="hidden"></div>  <div id="guide" class="$guide"></div>  <div id="watch"></div>  <div class="$applicationMessage"></div>  <div id="spinner" class="$spinner"></div>  <div class="$debug-watermark"></div>  <div id="dialog-stage"></div>  <div id="voice-search"></div>  <div class="$legend" id="legend"></div>  <div id="overlay-stage" class="$overlay-stage" data-hidden-by-default="true"></div>  <div class="$toaster"></div>  <div class="fps-placeholder"></div>  <div class="ui-stats-placeholder"></div>  <div class="font-demo-placeholder"></div>  <div id="automation-notifier"></div></div>',
            "airstream_tn2_app.html": '<div id="app-markup">  <div id="call-to-cast" class="$call-to-cast" data-hidden-by-default="true"></div>  <div id="surface" class="$surface"></div>  <div id="detail-surface" class="hidden"></div>  <div id="channel" class="hidden"></div>  <div id="search" class="hidden"></div>  <div id="watch"></div>  <div class="$applicationMessage"></div>  <div id="spinner" class="$spinner"></div>  <div class="$debug-watermark"></div>  <div id="dialog-stage"></div>  <div id="voice-search"></div>  <div class="$legend" id="legend"></div>  <div id="overlay-stage" class="$overlay-stage" data-hidden-by-default="true"></div>  <div class="$toaster"></div>  <div class="fps-placeholder"></div>  <div class="ui-stats-placeholder"></div>  <div class="font-demo-placeholder"></div>  <div id="automation-notifier"></div></div>',
