            "browse_horizontal_list.html": '<div>  <div class="no-content-message">    <div class="text">{{noContentMessage}}</div>  </div>  <div class="content">    <div class="$browse-list"></div>  </div></div>',
            "channel_button.html": '<div class="button" bedrock-style="background-image: url({{model.payload.imageUrl}})">{{model.payload.displayName}}</div>',
            "collage_thumbnail.html": '<div>  <div class="collage-thumbnail-column left collage-size-{{model.panes.length}}">    <div class="collage-thumbnail-image top $image"         data-image-url="{{model.panes[0].imageUrl}}"         data-background-color="{{model.panes[0].color}}"></div>    <div class="collage-thumbnail-image bottom $image"         data-image-url="{{model.panes[3].imageUrl}}"         data-background-color="{{model.panes[3].color}}"></div>  </div>\x3c!----\x3e<div class="collage-thumbnail-column right">    <div class="collage-thumbnail-image top $image" data-image-url="{{model.panes[1].imageUrl}}"         data-background-color="{{model.panes[1].color}}"></div>    <div class="collage-thumbnail-image bottom $image"         data-image-url="{{model.panes[2].imageUrl}}"         data-background-color="{{model.panes[2].color}}"></div>  </div></div>',
