            "endscreens/kids_talking_tom.html": '<div>  <div class="THEME-k end-screen left $image" data-image-url="call-to-cast-end-screen-kids-talking-tom.jpg">    <h3 class="call-to-cast-text">[[Tap a video to watch on your TV.|Tell kids that they should pick a video on the device to watch a video on the TV.]]</h3>  </div></div>',
            "endscreens/kids_theater.html": '<div>  <div class="THEME-k end-screen left $image" data-image-url="call-to-cast-end-screen-kids-theater.jpg">  </div></div>',
            "endscreens/music_party.html": '<div>  <div class="THEME-m end-screen music-party $image" data-image-url="call-to-cast-music.jpg">    <div class="$image call-to-cast-logo" data-image-url="call-to-cast-music-party-logo.png"></div>    <h3 class="call-to-cast-text">[[Need a soundtrack for your party?|Intro for the end screen for music highlighting the party use case.]]</h3>    <h3 class="call-to-cast-text">[[Stream endless video or audio stations to match the mood.|Description of the end screen for music highlighting the party use case.]]</h3>    <div class="$image footer" data-image-url="yt-music-logo-small.png"></div>  </div></div>',
