            "kabuki_keyboard.html": '<div>  <div id="microphone" class="$iconButton" aria-label="voice search"></div>  <div id="keyboard-grid" class="keyboard-grid $grid" data-catch-row-mouse-move="{{catchMouseMove}}" data-model="{{model.getLayout().rows}}" data-loop-rows="true" data-rate-limit="{{gridRateLimit}}" data-catch-mouse-move="true" data-enable-sounds="false"></div>  <div id="letter-suggest" class="letter-suggest $list" data-is-vertical="true" data-catch-mouse-move="true" data-model="{{letterSuggestions}}"></div></div>',
            "legend.html": '<div>  <div class="$legendItem airstream-back" data-legend-type="airstream-back"></div>  <div class="$legendItem back" data-legend-type="back"></div>  <div class="$legendItem back-to-top" data-legend-type="back-to-top"></div>  <div class="$legendItem exit" data-legend-type="exit"></div>  <div class="$legendItem reversed-back" data-legend-type="back"></div>  <div class="$legendItem search" data-legend-type="search"></div>  <div class="$legendItem space" data-legend-type="space"></div>  <div class="$legendItem home" data-legend-type="home"></div>  <div class="$legendItem modify" data-legend-type="modify"></div>  <div class="$legendItem next" data-legend-type="next"></div>  <div class="$legendItem delete" data-legend-type="delete"></div>  <div class="$legendItem guide" data-legend-type="guide"></div>  <div class="$legendItem close-guide" data-legend-type="close-guide"></div>  <div class="$legendItem voice-search" data-legend-type="voice-search"></div>  <div class="$legendItem voice-search-space" data-legend-type="voice-search-space"></div>  <div class="$legendItem toggle-video-info" data-legend-type="toggle-video-info"></div>  <div class="$legendItem add-to-watch-later" data-legend-type="add-to-watch-later"></div>  <div class="$legendItem osk" data-legend-type="osk"></div></div>',
            "legend_item.html": '<div>  <span class="icon {{iconClass}}"></span>  <span class="title">{{label}}</span></div>',
            "new_post_play.html": '<div>  <div class="$component post-play-left" data-model="{{model}}">    <div class="replay-video-icon material-icon-replay"></div>    <div class="replay-video-button $tiltable"         data-model="{{model}}">      <div class="$image" data-image-url="{{model.replayButton.imageUrl}}"></div>      <div class="$iconButton" data-model="{{model.replayButton}}"></div>    </div>    <div class="next-video-metadata">      <div class="next-video-heading">{{parent.getNextVideoHeading()}}</div>      <div class="next-video-title">{{model.previewTooltip.title}}</div>      <div class="next-video-channel">{{model.previewTooltip.byline}}</div>    </div>  </div>  <div class="$component post-play-right" data-model="{{model}}">    <div class="$tiltable-icon-button next-video-button" data-model="{{model.nextVideoButton}}"></div>    <div class="$image next-video-image" data-image-url="{{model.previewTooltip.imageUrl}}">        <div class="next-video-gradient"></div>    </div>  <div></div>',
            "new_search.html": '<div>    <div class="controls">      <div class="$on-screen-keyboard"></div>      <div id="text-box-background">        <div id="apple-search-icon" class="icon-search"></div>        <div id="search-input" class="$text-input-suggestion" data-title="search"></div>      </div>      <div class="search-bar-line"></div>      <div class="icon-container">        <div id="keyboard-icon" class="icon-search-keyboard"></div>      </div>      <div id="search-text-entry" class="$component">        <div id="search-keyboard" class="$search-keyboard"></div>        <div id="search-action" class="$subtitled-button search-action-button"></div>        <div class="$iconButton show-native-osk-button"></div>        <div class="suggestions-container">            <div id="search-suggestions" class="suggestions">              <div id="vertical-search-suggestions" class="$vertical-suggestions"></div>              <div id="horizontal-search-suggestions" class="$horizontal-suggestions"></div>            </div>        </div>      </div>    </div>    <div id="results-placeholder" role="grid"></div>    <div class="$iconButton left-back-button"></div>  </div>',
