            "auth/sign_in.html": '<div class="sign-in" aria-live="polite" aria-atomic="true">  <div class="mobile-assisted">    <div class="title waiting detected">      [[Sign in using the YouTube mobile app|Instructs user to begin the TV sign-in flow using the YouTube mobile app.]]    </div>    <div class="title access-allowed">      [[Signing in...|Notifies user that the TV is now signing in after detecting that a mobile device has completed the sign-in flow.]]    </div>    <div class="subtitle">      [[Tap your account|Instructs user to tap on the account icon on his/her mobile device.]]    </div>    <div class="graphic" title="image of mobile device"></div>    <div class="instructions">      [[Make sure your mobile device is on the same Wi-Fi network as this device|Instructs user to ensure that the mobile device and TV device are connected to the same Wi-Fi network.|166694285]]    </div>    <div class="status">      <div class="icon">        <div class="circle waiting"></div>        <div class="quarter waiting">          <div class="circle waiting"></div>        </div>      </div>      <div class="waiting">        [[Searching for device|Message indicating that the TV has not yet detected a mobile device that has initiated a sign-in flow.]]      </div>      <div class="detected access-allowed">{{model.getDeviceDescription()}}</div>    </div>  </div>  <div class="manual">    <div class="title">{{manualDialogTitle}}</div>    <div class="step">      <div class="instructions">        1. [[On your phone or computer, go to|Instructs user to use a phone or computer to navigate to the following URL.]]      </div>      <div class="sign-in-url">youtube.com/activate</div>    </div>    <div class="step">      <div class="instructions">        2. [[Sign in with your Google account, then enter|Instructs user to sign in with his/her Google account, then enter the following code.]]:      </div>      <div class="activation-code {{authCodeLength}}">{{authCode}}</div>    </div>  </div>  <div class="error">    <div class="title">      [[Something went wrong|Sign-in dialog title when there is an authentication server error.]]    </div>    <div>      [[Sign in is temporarily unavailable. Please try again later.|Error message displayed when the TV fails to fetch an auth code.]]    </div>  </div>  <div class="sign-in-buttons">    <div class="$sign-in-buttons-list" data-model="{{model.getButtons()}}"></div>  </div></div>',
